use base64::{engine::general_purpose, Engine as _};
use flate2::read::GzDecoder;
use std::io::Read;

pub const COMPRESSED_INVENTORY: &str = "";

pub fn load_inventory() -> Option<Vec<Vec<String>>> {
    let decoded = general_purpose::STANDARD.decode(COMPRESSED_INVENTORY).ok()?;
    let mut decoder = GzDecoder::new(&decoded[..]);
    let mut json_str = String::new();
    decoder.read_to_string(&mut json_str).ok()?;
    serde_json::from_str(&json_str).ok()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_load_inventory() {
        let inv = load_inventory().expect("Failed to load inventory");
        assert!(!inv.is_empty());
        assert_eq!(inv[0].len(), 2);
    }
}
